function norm(s) {
  return (s ?? "").toString().trim().replace(/\s+/g, " ");
}

function limpiarEmail(email) {
  let e = norm(email).toLowerCase();
  e = e.replace(/^mailto:/i, "").replace(/[<>]/g, "");
  e = e.split(/\s+/)[0] || "";
  return e;
}

function validarEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email);
}

function limpiarDocumento(valor) {
  return norm(valor).toUpperCase().replace(/[^A-Z0-9]/g, "");
}

function validarDniNie(valor) {
  const v = limpiarDocumento(valor);
  const dniRe = /^\d{8}[A-Z]$/;
  const nieRe = /^[XYZ]\d{7}[A-Z]$/;
  const letras = "TRWAGMYFPDXBNJZSQVHLCKE";

  if (dniRe.test(v)) {
    const num = parseInt(v.slice(0, 8), 10);
    return letras[num % 23] === v.slice(8);
  }

  if (nieRe.test(v)) {
    const map = { X: "0", Y: "1", Z: "2" };
    const num = parseInt(map[v[0]] + v.slice(1, 8), 10);
    return letras[num % 23] === v.slice(8);
  }

  return false;
}

function splitNombreApellidos(nombre, apellidos, nombreCompleto) {
  let n = norm(nombre);
  let a = norm(apellidos);

  if ((!n || !a) && nombreCompleto) {
    const full = norm(nombreCompleto);
    if (full.includes(",")) {
      const [ap, nom] = full.split(",").map((x) => norm(x));
      n = n || nom;
      a = a || ap;
    } else {
      const parts = full.split(" ").filter(Boolean);
      if (!n && parts.length) n = parts[0];
      if (!a && parts.length > 1) a = parts.slice(1).join(" ");
    }
  }

  if (n && !a && n.includes(" ")) {
    const parts = n.split(" ").filter(Boolean);
    n = parts[0];
    a = parts.slice(1).join(" ");
  }

  return { nombre: n, apellidos: a };
}

function aplicarDuplicadosEnLote(lista, getEmail, getDni, setError, getErrores) {
  const seenEmail = new Map();
  const seenDni = new Map();

  lista.forEach((obj, idx) => {
    const email = getEmail(obj);
    const dni = getDni(obj);

    if (email && validarEmail(email)) {
      if (seenEmail.has(email)) {
        const firstIdx = seenEmail.get(email);
        setError(obj, `Email duplicado en el fichero (repite fila/item ${firstIdx + 1})`, getErrores(obj));
      } else {
        seenEmail.set(email, idx);
      }
    }

    if (dni && validarDniNie(dni)) {
      if (seenDni.has(dni)) {
        const firstIdx = seenDni.get(dni);
        setError(obj, `DNI/NIE duplicado en el fichero (repite fila/item ${firstIdx + 1})`, getErrores(obj));
      } else {
        seenDni.set(dni, idx);
      }
    }
  });
}

// 1) Si viene agrupado en datos_normalizados[]
if (Array.isArray(items?.[0]?.json?.datos_normalizados)) {
  const base = { ...items[0].json };

  // ✅ asegura ctx si existe
  const ctx = items[0].json?.ctx ?? null;

  const rows = base.datos_normalizados;
  delete base.datos_normalizados;

  const out = rows.map((r, idx) => {
    const src = r ?? {};
    const { nombre, apellidos } = splitNombreApellidos(
      src.nombre,
      src.apellidos,
      src.nombre_completo || src.nombreCompleto
    );

    const dni = limpiarDocumento(src.dni || src.nif || src.nie || "");
    const email = limpiarEmail(src.email || src.correo || "");

    const errores = [];
    if (!nombre) errores.push("Falta nombre");
    if (!apellidos) errores.push("Faltan apellidos");
    if (!dni) errores.push("Falta DNI/NIE");
    if (dni && !validarDniNie(dni)) errores.push("DNI/NIE inválido");
    if (!email) errores.push("Falta email");
    if (email && !validarEmail(email)) errores.push("Email inválido");

    return {
      json: {
        ...base,
        ...(ctx ? { ctx } : {}),
        ...src,
        nombre,
        apellidos,
        dni,
        email,
        errores,
        valido: errores.length === 0,
        _fila_excel: idx + 1,
      },
      // ✅ no perder binary del email/adjunto
      binary: items[0].binary,
    };
  });

  aplicarDuplicadosEnLote(
    out,
    (it) => it.json.email,
    (it) => it.json.dni,
    (it, msg, errs) => {
      errs.push(msg);
      it.json.valido = false;
    },
    (it) => it.json.errores
  );

  return out;
}

// 2) Caso normal
const out = items.map((item, idx) => {
  const src = item.json?.normalizado ?? item.json ?? {};

  const { nombre, apellidos } = splitNombreApellidos(
    src.nombre,
    src.apellidos,
    src.nombre_completo || src.nombreCompleto
  );

  const dni = limpiarDocumento(src.dni || src.nif || src.nie || "");
  const email = limpiarEmail(src.email || src.correo || "");

  const errores = [];
  if (!nombre) errores.push("Falta nombre");
  if (!apellidos) errores.push("Faltan apellidos");
  if (!dni) errores.push("Falta DNI/NIE");
  if (dni && !validarDniNie(dni)) errores.push("DNI/NIE inválido");
  if (!email) errores.push("Falta email");
  if (email && !validarEmail(email)) errores.push("Email inválido");

  item.json.nombre = nombre;
  item.json.apellidos = apellidos;
  item.json.dni = dni;
  item.json.email = email;
  item.json.errores = errores;
  item.json.valido = errores.length === 0;
  item.json._item_index = idx + 1;

  return item; // ✅ mantiene binary
});

aplicarDuplicadosEnLote(
  out,
  (it) => it.json.email,
  (it) => it.json.dni,
  (it, msg, errs) => {
    errs.push(msg);
    it.json.valido = false;
  },
  (it) => it.json.errores
);

return out;

function norm(s) {
  return (s ?? "").toString().replace(/\s+/g, " ").trim();
}

function stripAccents(s) {
  return (s || "").normalize("NFD").replace(/[\u0300-\u036f]/g, "");
}

function cleanPasswordToken(s) {
  return stripAccents(norm(s))
    .toLowerCase()
    .replace(/[^a-z0-9]/g, "");
}

function passwordFromApellidos(apellidosRaw) {
  const apellidos = norm(apellidosRaw).toLowerCase();
  if (!apellidos) return "";

  const tokens = apellidos.split(" ").filter(Boolean);

  const conectores = new Set([
    "de","del","la","las","los","da","do","dos","das","di","van","von","y","e"
  ]);

  const t1 = tokens[0] || "";
  const t2 = tokens[1] || "";

  if (!t2) return cleanPasswordToken(t1);

  const t1c = cleanPasswordToken(t1);

  if (conectores.has(t1c) || t1c.length < 3) {
    return cleanPasswordToken(t1 + t2);
  }

  return t1c;
}

function splitNombreApellidos(nombreRaw, apellidosRaw) {
  let nombre = norm(nombreRaw);
  let apellidos = norm(apellidosRaw);

  if (!apellidos && nombre) {
    const parts = nombre.split(" ").filter(Boolean);
    if (parts.length >= 2) {
      nombre = parts[0];
      apellidos = parts.slice(1).join(" ");
    }
  }

  return { nombre, apellidos };
}

const out = [];

for (const item of $input.all()) {
  const j = item.json || {};

  const { nombre, apellidos } = splitNombreApellidos(j.nombre, j.apellidos);

  const dniUpper = norm(j.dni).toUpperCase().replace(/\s+/g, "");
  const dniLower = dniUpper.toLowerCase();
  const email = norm(j.email).toLowerCase();

  let password = passwordFromApellidos(apellidos);
  if (!password) password = dniLower || dniUpper;

  if (!nombre || !apellidos || !dniUpper || !email || !password) continue;

  out.push({
    json: {
      // ✅ SOLO CAMPOS DEL CSV (sin ctx, sin ticket_id, sin empresa_id)
      firstname: nombre,
      lastname: apellidos,
      username: dniLower,
      password,
      email,
      city: "MADRID",
      course1: "",
      type1: 1,

      // ✅ profile fields correctos
      profile_field_TD: "D",
      profile_field_ND: dniUpper,
      profile_field_LD: ""
    }
  });
}

return out;

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

return items.map(item => {
  // 1) ticket_id
  const ticket_id = uuidv4();

  // 2) dominio desde _meta_email.to (Modelo A)
  const to = item.json._meta_email?.to || "";
  const match = to.match(/@([a-zA-Z0-9.-]+)/);
  const dominio = match ? match[1].toLowerCase() : null;

  // 3) mapping dominio -> empresa_id
  const empresas = {
    "harveylluch.com": "f77ce600-761e-4461-945e-b305c2df7c1a",
  };

  const empresa_id = dominio ? (empresas[dominio] || null) : null;

  // 4) guardar en raíz (compat) + ctx (pro)
  item.json.ticket_id = ticket_id;
  item.json.empresa_id = empresa_id;

  item.json.ctx = {
    ticket_id,
    empresa_id,
    dominio_to: dominio,
    meta_email: item.json._meta_email || null,
  };

  return item;
});

// 1) Base del ticket (primer item)
const base = items[0]?.json ?? {};

// 2) Meta email: primero _meta_email (estable), si no, trigger
const mail = base._meta_email
  ?? $items("Email Trigger (IMAP)")[0]?.json
  ?? {};

// 3) ctx: si ya venía, lo usamos; si no, lo creamos
const ctx = base.ctx ?? {
  ticket_id: base.ticket_id ?? null,
  empresa_id: base.empresa_id ?? null,
};

// 4) Construimos filas normalizadas (ojo: tu normalizado está en item.json.normalizado)
const filas = items.map((i, idx) => {
  const n = i.json.normalizado ?? {};

  return {
    fila: i.json.fila ?? i.json._fila_excel ?? (idx + 1),
    nombre: n.nombre ?? i.json.nombre ?? null,
    apellidos: n.apellidos ?? i.json.apellidos ?? null,
    dni: n.dni ?? i.json.dni ?? null,
    email: n.email ?? i.json.email ?? null,
    valido: i.json.valido ?? false,
    errores: i.json.errores ?? [],
  };
});

// 5) Filas inválidas
const invalidas = filas.filter(f => f.valido === false);

// 6) Estado final
const estado = invalidas.length ? "ERROR_VALIDACION" : "PENDIENTE_ALTA";

// 7) Resultado consolidado
return [{
  json: {
    // 🔥 ctx (fuente única para todo el flujo)
    ctx,

    // 🔐 Meta ticket (plano también, por compat)
    ticket_id: ctx.ticket_id,
    empresa_id: ctx.empresa_id,
    estado,

    // 📧 Meta email
    fecha_email: mail.date ?? null,
    remitente: mail.from ?? null,
    asunto: mail.subject ?? null,

    // 📊 Datos del Excel
    datos_normalizados: filas,

    hay_errores_validacion: invalidas.length > 0,
    errores_validacion: invalidas,

    motivo_error: invalidas.length
      ? `Validación fallida: ${invalidas.length} fila(s) con errores`
      : null,

    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  },
  // ✅ no rompas binarios si alguien los necesita luego
  binary: items[0].binary,
}];

return items.map(item => {
  const date =
    item.json.date ??
    item.json.dateTime ??
    item.json.internalDate ??
    item.json.headers?.date ??
    null;

  const from =
    item.json.from?.text ??
    item.json.from ??
    item.json.headers?.from ??
    "";

  const to =
    item.json.to?.text ??
    item.json.to ??
    item.json.headers?.to ??
    "";

  const subject =
    item.json.subject ??
    item.json.headers?.subject ??
    null;

  // ✅ message-id (puede venir en varias formas)
  const message_id =
    item.json.headers?.["message-id"] ??
    item.json.headers?.["Message-ID"] ??
    item.json.headers?.["Message-Id"] ??
    item.json.messageId ??
    item.json.message_id ??
    null;

  let empresa_id = null;

  if (to.toLowerCase().includes("@harveylluch.com")) {
    empresa_id = "f77ce600-761e-4461-945e-b305c2df7c1a";
  }

  item.json._meta_email = { date, from, to, subject, message_id };
  item.json.empresa_id = empresa_id;

  // ✅ para usarlo directo en expresiones
  item.json.message_id = message_id;

  return item;
});

// Recuperamos el ticket y metadata del nodo anterior al XLSX
const meta = $items("Generar_ticket_id")[0]?.json ?? {};

// Helpers
function normKey(k) {
  return String(k ?? "")
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, "_")
    .replace(/[\/]/g, "_")
    .replace(/[-]/g, "_")
    .trim();
}

function getValByAliases(row, aliases) {
  const keys = Object.keys(row || {});
  for (const k of keys) {
    const nk = normKey(k);
    if (aliases.includes(nk)) return row[k];
  }
  return "";
}

function splitNombreApellidos(fullRaw) {
  const full = String(fullRaw ?? "").trim();
  if (!full) return { nombre: "", apellidos: "" };

  if (full.includes(",")) {
    const [ap, nom] = full.split(",").map(s => s.trim());
    return { nombre: nom ?? "", apellidos: ap ?? "" };
  }

  const parts = full.split(/\s+/).filter(Boolean);
  if (parts.length === 1) return { nombre: parts[0], apellidos: "" };
  return { nombre: parts[0], apellidos: parts.slice(1).join(" ") };
}

function limpiarEmail(email) {
  let e = (email ?? "").toString().trim();
  e = e.replace(/^mailto:/i, "").replace(/[<>]/g, "");
  e = e.split(/\s+/)[0] || "";
  return e.toLowerCase();
}

// Aliases
const ALIASES = {
  nombre: ["nombre"],
  apellidos: ["apellidos"],
  nombre_completo: [
    "nombre_y_apellidos",
    "nombre_completo",
    "nombre_apellidos",
    "trabajador",
    "empleado",
    "nombre_y_apellido",
  ],
  dni: [
    "dni",
    "dni_nie",
    "dni/nie",
    "dni_nie_",
    "nif",
    "nie",
    "documento",
    "numero_documento",
  ],
  email: [
    "email",
    "correo",
    "correo_electronico",
    "e_mail",
    "mail",
    "email_corporativo",
    "correo_corporativo",
  ],
  username: ["username", "usuario", "user", "login"],
  firstname: ["firstname", "first_name"],
  lastname: ["lastname", "last_name"],
};

return items.map(item => {
  const src = item.json ?? {};
  const row = (src.raw_row && typeof src.raw_row === "object") ? src.raw_row : src;

  const nombreDirecto = getValByAliases(row, ALIASES.nombre);
  const apellidosDirecto = getValByAliases(row, ALIASES.apellidos);

  const firstname = getValByAliases(row, ALIASES.firstname);
  const lastname = getValByAliases(row, ALIASES.lastname);

  const nombreCompleto = getValByAliases(row, ALIASES.nombre_completo);

  let nombre = String(nombreDirecto ?? "").trim();
  let apellidos = String(apellidosDirecto ?? "").trim();

  if ((!nombre && !apellidos) && (firstname || lastname)) {
    nombre = String(firstname ?? "").trim();
    apellidos = String(lastname ?? "").trim();
  }

  if ((!nombre && !apellidos) && nombreCompleto) {
    const sp = splitNombreApellidos(nombreCompleto);
    nombre = sp.nombre;
    apellidos = sp.apellidos;
  }

  const dni = String(getValByAliases(row, ALIASES.dni) ?? "")
    .toUpperCase()
    .replace(/\s+/g, "")
    .trim();

  const email = limpiarEmail(getValByAliases(row, ALIASES.email));
  const username = String(getValByAliases(row, ALIASES.username) ?? "").trim();

  const normalizado = { nombre, apellidos, dni, email, username };

  return {
    json: {
      ...src,           // primero lo que venga de extract
      ...meta,          // ✅ meta manda SIEMPRE (ticket_id/empresa_id/ctx)
      nombre,
      apellidos,
      dni,
      email,
      username,
      normalizado,
    },
    binary: item.binary, // ✅ no pierdes binary
  };
});

const src =
  $json.filas ??
  $json.datos_normalizados ??
  $json.validos ??
  $json.rows ??
  [];

if (!Array.isArray(src)) {
  throw new Error("No encuentro un array de filas (filas/datos_normalizados/validos/rows).");
}

// Base/ctx para no perder contexto
const base = {
  ctx: $json.ctx ?? null,
  ticket_id: $json.ticket_id ?? null,
  empresa_id: $json.empresa_id ?? null,
  fecha_email: $json.fecha_email ?? null,
  remitente: $json.remitente ?? null,
  asunto: $json.asunto ?? null,
};

// Solo válidas (si no existe campo, las deja pasar)
const validas = src.filter(f => (f?.valido === undefined ? true : f.valido === true));

return validas.map(f => ({
  json: {
    ...base,
    ...f,
  },
}));
